function activeCollapse(){if(document.querySelector(".stocks__description")){let e,t=document.querySelector(".stocks__description").querySelector(".stocks__description-text-wrapper"),o=document.querySelector(".stocks__collapse-btns"),s=document.querySelector(".stocks__description-text");e=window.innerWidth>768?100:window.innerWidth>520?90:180,s.offsetHeight>e?(o.style.display="block",t.style.height=e+"px"):o.style.display="none"}}function showText(){let e=document.querySelector(".stocks__description-text-wrapper"),t=document.querySelector(".stocks__description-text");e.style.height=t.offsetHeight+5+"px"}function hideText(){let e,t=document.querySelector(".stocks__description-text-wrapper");e=window.innerWidth>768?100:window.innerWidth>520?90:180,t.style.height=e+"px"}function setCollapseButtonsEvents(){if(document.querySelector(".stocks__collapse-btns")){let e=document.querySelector(".stocks__collapse-btns"),t=e.querySelector(".stocks__collapse-btns-show"),o=e.querySelector(".stocks__collapse-btns-hide");t.addEventListener("click",function(){e.dataset.active="true",showText()}),o.addEventListener("click",function(){delete e.dataset.active,hideText()})}}window.addEventListener("resize",function(){activeCollapse()}),window.addEventListener("DOMContentLoaded",function(){setCollapseButtonsEvents(),activeCollapse()}),window.addEventListener("load",function(){activeCollapse()});